return items.map((item) => {
  const c=item.json;
  const first=String(c.nome||'').trim().split(/\s+/)[0];
  const hi=first ? `Oi, ${first}!` : 'Oi!';
  const etapa=String(c.etapa||'');
  const segunda=Number(c.tentativa)===2;
  let body='';
  if (etapa==='ESCOLHENDO_VAGA' || etapa==='PRIMEIRO_CONTATO') body='Vi que você iniciou o atendimento, mas não concluiu a escolha da vaga. Ainda deseja continuar?';
  else if (etapa==='PERGUNTANDO_EXPERIENCIA') body='Para continuarmos, ainda falta confirmar sua experiência para a vaga escolhida. Podemos seguir?';
  else if (etapa==='AGUARDANDO_CTPS_CEP') body='Para continuar, ainda faltam seu CEP e a CTPS Digital enviada como Documento PDF. O currículo é opcional, mas não substitui a CTPS.';
  else if (etapa==='AGUARDANDO_CTPS') body='Seu processo está quase completo. Ainda falta enviar a CTPS Digital como Documento PDF.';
  else if (etapa==='AGUARDANDO_CEP') body='Recebemos seu documento. Ainda falta informar seu CEP com 8 números para continuar.';
  else if (etapa==='AGUARDANDO_APRESENTACAO') body='Você avançou na triagem. Ainda deseja continuar e enviar uma breve apresentação profissional?';
  else body='Sua candidatura continua aguardando a escolha do horário da entrevista. Deseja ver as opções novamente?';
  const ending=segunda ? '\n\nPara não incomodar, vou pausar os lembretes por enquanto. Quando quiser continuar, basta mandar uma mensagem por aqui.' : '';
  return {json:{...c,session:'whats_junior',chatId:String(c.telefone||'').replace(/\D/g,'')+'@c.us',text:`${hi} ${body}${ending}`}};
});
